#include <stdio.h>

#define N 4

/* Round-Robin Q=2 avec 4 processus arrivant a t=0.
 * Algorithme :
 *   Repeter tant que done < N :
 *     Pour chaque processus i :
 *       Si remaining[i] > 0 :
 *         run = min(remaining[i], quantum)  /* le processus ne peut depasser son quantum */
 *         time += run
 *         remaining[i] -= run
 *         Si remaining[i] == 0 : response[i] = time, done++
 */
int main(void) {
    int burst[]    = {12, 8, 4, 10};
    int remaining[N];
    int response[N];
    int quantum    = 2;
    int time       = 0;
    int done       = 0;

    for (int i = 0; i < N; i++) {
        remaining[i] = burst[i];
        response[i]  = -1;
    }

    while (done < N) {
        for (int i = 0; i < N; i++) {
            if (remaining[i] > 0) {
                int run = (remaining[i] < quantum) ? remaining[i] : quantum;
                time += run;
                remaining[i] -= run;
                if (remaining[i] == 0) {
                    response[i] = time;
                    done++;
                }
            }
        }
    }

    for (int i = 0; i < N; i++)
        printf("Response time P%d: %d\n", i + 1, response[i]);

    float avg = (float)(response[0] + response[1] + response[2] + response[3]) / N;
    printf("Average response time: %.2f\n", avg);
    return 0;
}

